// Meta Ad Accounts per brand — fill in actual account IDs after setup
const accounts = [
  { slug: 'thiocyn',     ad_account_id: 'act_REPLACE_THIOCYN_ID',     market: 'DE' },
  { slug: 'thiocyn',     ad_account_id: 'act_REPLACE_THIOCYN_US_ID',  market: 'US' },
  { slug: 'take-a-shot', ad_account_id: 'act_REPLACE_TAS_ID',         market: 'DE' },
  { slug: 'dr-severin',  ad_account_id: 'act_REPLACE_DRSEV_ID',       market: 'DE' },
  { slug: 'paigh',       ad_account_id: 'act_REPLACE_PAIGH_ID',       market: 'DE' },
  { slug: 'wristr',      ad_account_id: 'act_REPLACE_WRISTR_ID',      market: 'DE' }
];
return accounts.map(a => ({ json: a }));

// Parse Meta Insights response and compute KPIs
const brand_slug = $('Ad Account List').first().json.slug;
const market     = $('Ad Account List').first().json.market;
const data       = $input.first().json.data?.[0] || {};

const spend       = parseFloat(data.spend || 0);
const impressions = parseInt(data.impressions || 0);
const clicks      = parseInt(data.clicks || 0);
const reach       = parseInt(data.reach || 0);
const cpm         = parseFloat(data.cpm || 0);
const ctr         = parseFloat(data.ctr || 0);

// Extract purchases from actions
const actions       = data.actions || [];
const purchaseAction = actions.find(a => a.action_type === 'purchase');
const purchases     = purchaseAction ? parseInt(purchaseAction.value) : 0;

// Extract revenue from action_values
const actionValues  = data.action_values || [];
const revenueAction = actionValues.find(a => a.action_type === 'purchase');
const revenue       = revenueAction ? parseFloat(revenueAction.value) : 0;

const roas = spend > 0 ? Math.round((revenue / spend) * 100) / 100 : 0;

const today = new Date().toISOString().split('T')[0];
const yesterday = new Date(Date.now() - 86400000).toISOString().split('T')[0];

return [{
  json: {
    brand_slug, market,
    date: yesterday,
    spend, impressions, clicks, reach, cpm, ctr, roas,
    purchases, revenue,
    platform: 'meta',
    updated_at: new Date().toISOString()
  }
}];
